ReportUtil = {}

local function getPlayerLevelInterval(player)
    if player.level == 1 then
        return "1"
    elseif player.level == 2 then
        return "2"
    elseif player.level >= 3 and player.level <= 7 then
        return "3_7"
    elseif player.level >= 8 and player.level <= 15 then
        return "8_15"
    elseif player.level >= 16 then
        return "16"
    end
end

local function getPlayerGameTime()
    local minute = RewardManager:getGameRunningTime() / 60
    if minute <= 1 then
        return "0_1_minutes"
    elseif minute > 1 and minute <= 3 then
        return "1_3_minutes"
    elseif minute > 3 and minute <= 6 then
        return "3_6_minutes"
    elseif minute > 6 and minute <= 10 then
        return "6_10_minutes"
    elseif minute > 10 and minute <= 15 then
        return "10_15_minutes"
    elseif minute > 15 and minute <= 20 then
        return "15_20_minutes"
    elseif minute > 20 and minute <= 30 then
        return "20_30_minutes"
    else
        return "30_INF_minutes"
    end
end

local function getPlayerDayPart(player)
    if player.play_days > 30 then
        return "Day30a"
    else
        return "Day" .. player.play_days
    end
end

local function getRefreshTimes(times)
    if times > 20 then
        return "Times20a"
    else
        return "Times" .. times
    end
end

function ReportUtil.reportWatchAdFinish(player, AdKey)
    local app = "MainApp"
    if player.enableIndie then
        app = "IndieApp"
    end
    local parts = { "g1046WatchAd", app, AdKey, getPlayerDayPart(player) }
    GameAnalytics:design(player.userId, player.level, parts)
end

