function ReportUtil.reportLotteryRefreshTimes(player)
    local app = "MainApp"
    if player.enableIndie then
        app = "IndieApp"
    end
    local info = GameLottery.LotteryInfo[tostring(player.userId)]
    if not info then
        return
    end
    local times = info.lotteryRefreshTimes
    local parts = { "g1046LotteryRefreshTimes", app, getRefreshTimes(times), getPlayerDayPart(player) }
    GameAnalytics:design(player.userId, player.level, parts)
    if times > 50 then
        ReportUtil.reportLotteryMVP(player)
    end
end

function ReportUtil.reportLotteryMVP(player)
