function ReportUtil.reportDeathReason(player, level, damageType, itemId)
    if not player.isPartyUser then
        if BlackBoard:getValue("GameType") == "PlayerGame" then
            if damageType == "player" then
                GameAnalytics:design(player.userId, 1, { "Player_deathReason", level, "PlayerKill", tostring(itemId) })
            else
                GameAnalytics:design(player.userId, 1, { "Player_deathReason", level, "Other", tostring(damageType) })
            end
        else
            if AIManager:isAI(player.rakssid) == true then
                return
            end
            if damageType == "player" then
                GameAnalytics:design(player.userId, 1, { "AI_killplayers", getPlayerGameTime(), "PlayerKill", tostring(itemId) })
            else
                GameAnalytics:design(player.userId, 1, { "AI_killplayers", getPlayerGameTime(), "Other", tostring(damageType) })
            end
        end
    end
end

function ReportUtil.reportAIDamageBed(isAIBed)
    local players = PlayerManager:getPlayers()
    for _, player in pairs(players) do
        if player and AIManager:isAI(player.rakssid) == false then
            if isAIBed then
                GameAnalytics:design(player.userId, 1, { "AI_damageBed", "AI_Bed" })
            else
                GameAnalytics:design(player.userId, 1, { "AI_damageBed", "Player_Bed" })
            end
            break
        end
    end
end

function ReportUtil.reportAIGameEndTime()
