function ReportUtil.reportTotalPacketInfo(player)
    local gameType = BlackBoard:getValue("GameType")
    if not gameType then
        return
    end
    if AIManager:isAI(player.rakssid) then
        return
    end
    local data = DataBuilder.new():fromData(ServerNetwork.Instance():getSendTotalPacketInfo())
    local TotalPacketCount = data:getNumberParam("TotalPacketCount")
    local TotalPacketByte = data:getNumberParam("TotalPacketByte")
    GameAnalytics:design(player.userId, TotalPacketCount, { "TotalPacketInfo", gameType, "PacketCount" })
    GameAnalytics:design(player.userId, TotalPacketByte, { "TotalPacketInfo", gameType, "PacketByte" })
    GameAnalytics:design(player.userId, os.time() - GameMatch.startGameTime, { "TotalPacketInfo", gameType, "GameTime" })
end

