function ReportUtil.reportPlayerLicenseLvUp(player, level)
    if level == 1 then
        GameAnalytics:design(player.userId, 1, { "License_Lv", 1 })
        return
    end
    local Interval, IntervalChange = GameLicense:calculateLevelInterval(level)
    if IntervalChange then
        GameAnalytics:design(player.userId, -1, { "License_Lv", IntervalChange })
        GameAnalytics:design(player.userId, 1, { "License_Lv", Interval })
    end
end

